class Solution(object):
    def decodeCiphertext(self, encodedText, rows):
        """
        :type encodedText: str
        :type rows: int
        :rtype: str
        """
        # pre-process
        # short cut
        if rows == 1:
            return encodedText

        L = len(encodedText)
        M = rows
        N = L // M
        matrix = [[' '] * N for _ in range(M)]
        for x in range(M):
            for y in range(N):
                idx = x * N + y
                matrix[x][y] = encodedText[idx]
        # print(matrix)

        # process
        ans = ""
        offset = 0
        while offset < N:
            x, y = 0, offset
            while x < M and y < N:
                ans += matrix[x][y]
                x += 1
                y += 1
            offset += 1
        ans = ans.rstrip()
        return ans


